ity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"section-assaults-body-20260717","layout":"single","locked":false,"modules":[{"id":"module-assaults-body-20260717","name":"","text":"<h1>Assaults</h1><h2>How Marinoff &amp; Associates Can Help</h2><p>At Marinoff &amp; Associates, we know that an assault charge can arise from a single moment – an argument, a misunderstanding, or an act of self-defense – and still carry consequences that follow you for years.</p><p>Our experienced legal team investigates the full story behind the charge, including witness accounts, injuries, self-defense claims, and police procedure, to build the strongest available defense.</p><h2>What Are Assault Charges?</h2><p>Assault charges can range from misdemeanor offenses involving minor injury or threats to serious felony charges involving significant injury or weapons, and more. These are only examples. We can help with these and any other related charge.</p><h2>How We Can Help:</h2><ul><li><p><strong>Court Representation:</strong> We can represent you at all stages of the legal process, from advisement and pre-trial hearings through trial, working to protect your rights at every step.</p></li><li><p><strong>Self-Defense &amp; Justification:</strong> Where the facts support it, we can develop defenses based on self-defense, defense of others, or lack of intent.</p></li><li><p><strong>Challenging Evidence:</strong> We can scrutinize witness statements, medical records, video, and police reports for inconsistencies and constitutional violations.</p></li><li><p><strong>Negotiations &amp; Settlements:</strong> In some cases, we may work to negotiate reduced charges, deferred resolutions, or alternatives that protect your record and future.</p></li></ul><p>If you or a loved one is facing an assault charge, contact Marinoff &amp; Associates today for a consultation.</p>","type":"text","column":"","settings":{}}]},{"id":"b22a4855-b26c-43e3-9a2c-06dcfd7af403","title":"Footer","layout":"three-column","locked":false,"modules":[{"id":"module_1781127640512_v48dw","name":"Contact Us","text":"<h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Contact Us</strong></span></h3><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">303.619.1978‬</span></p><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">720.621.7635 - Se Habla Español</span></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"mailto:bmarinoff@brandonmarinoff.com\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">bmarinoff@brandonmarinoff.com</span></a></p><p></p><h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Address</strong></span></h3><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">12207 Pecos St. Suite 700</span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">Westminster, CO. 80234</span></a></p>","type":"text","column":"right","settings":{"text":"Contact Us","align":"left","textColor":"#173c61","headlineId":"","headingLevel":"H3"}},{"id":"module_1781293635840_3p0km","name":"Logo","text":"","type":"image","column":"left","settings":{"alt":"Brandon Marinoff & Associates","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_As