ity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"section-federal-crimes-body-20260717","layout":"single","locked":false,"modules":[{"id":"module-federal-crimes-body-20260717","name":"","text":"<h1>Federal Crimes</h1><h2>How Marinoff &amp; Associates Can Help</h2><p>At Marinoff &amp; Associates, we understand that facing a federal investigation or indictment is different from facing state charges. Federal cases involve federal agencies, federal sentencing guidelines, and prosecutors with substantial resources, and they demand an early, strategic defense.</p><p>Our experienced legal team can guide you from the first contact by investigators through every stage of a federal case, protecting your rights and your future.</p><h2>What Are Federal Crimes?</h2><p>Federal charges can include fraud involving federal programs or interstate commerce, drug conspiracies, firearms offenses, immigration-related offenses, and other crimes prosecuted in federal court, and more. These are only examples. We can help with these and any other related charge.</p><h2>How We Can Help:</h2><ul><li><p><strong>Early Intervention:</strong> If you learn you are under federal investigation, we can engage early, advise you before you speak to investigators, and work to influence charging decisions.</p></li><li><p><strong>Federal Court Representation:</strong> We can represent you at all stages of a federal case, from initial appearance and detention hearings through trial.</p></li><li><p><strong>Sentencing Advocacy:</strong> Federal sentencing is driven by detailed guidelines. We can develop mitigation and advocate for the lowest available sentence when that stage cannot be avoided.</p></li><li><p><strong>Parallel Consequences:</strong> We can help you understand how a federal case may affect immigration status, professional licenses, and assets.</p></li></ul><p>If you or a loved one is facing a federal investigation or charge, contact Marinoff &amp; Associates today for a consultation.</p>","type":"text","column":"","settings":{}}]},{"id":"b22a4855-b26c-43e3-9a2c-06dcfd7af403","title":"Footer","layout":"three-column","locked":false,"modules":[{"id":"module_1781127640512_v48dw","name":"Contact Us","text":"<h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Contact Us</strong></span></h3><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">303.619.1978‬</span></p><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">720.621.7635 - Se Habla Español</span></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"mailto:bmarinoff@brandonmarinoff.com\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">bmarinoff@brandonmarinoff.com</span></a></p><p></p><h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Address</strong></span></h3><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">12207 Pecos St. Suite 700</span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">Westminster, CO. 80234</span></a></p>","type":"text","column":"right","settings":{"text":"Contact Us","align":"left","textColor":"#173c61","headlineId":"","headingLevel":"H3"}},{"id":"module_1781293635840_3p0km","name":"Logo","text":"","type":"image","column":"le