ity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Our Team - Dedicated Advocates","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Our Team</h1><h2>Dedicated Advocates. Compassionate Counsel. Trusted Representation.</h2><p>At <strong>Marinoff &amp; Associates, P.C</strong>., we believe that exceptional legal representation begins with exceptional people. Our team is committed to providing knowledgeable, personalized, and compassionate legal services to individuals and families throughout Colorado. We understand that legal matters are often stressful, emotional, and life-changing, which is why we work closely with every client to provide clear guidance, honest communication, and strong advocacy every step of the way.</p><p>Whether you are facing criminal charges or dealing with complex immigration issues, our team is here to listen, answer your questions, and help you move forward with confidence. We take pride in building meaningful relationships with our clients and treating every case with the attention, care, and dedication it deserves.</p><p></p><h1>A Team Approach to Your Success</h1><p>At <strong>Marinoff &amp; Associates, P.C</strong>., you are never just another case number. We work collaboratively to ensure that every detail of your matter is carefully reviewed, and every legal strategy is thoughtfully developed. By combining experience, preparation, and a client-focused approach, we strive to deliver practical solutions and the strongest possible representation.</p><p><strong>Our team is dedicated to:</strong></p><ul><li><p>Providing personalized attention and responsive communication</p></li><li><p>Protecting your rights and advocating for your best interests</p></li><li><p>Offering compassionate support during difficult times</p></li><li><p>Developing strategic legal solutions tailored to your unique circumstances</p></li><li><p>Guiding you through the legal process with clarity and confidence</p></li></ul><p></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Justice","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782513892737_Marinoff_and_Associates_-_Our_Team_of_Attorneys.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}},{"id":"module-1bf1973f-fb8e-4910-8211-fa79379ef999","name":"","text":"","type":"image","column":"right","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782675914413_Learn_ABout_Brandon_Marinoff.png","size":"100","effect":"none","newTab":"false","linkUrl":"/brandon-marinoff-bio","variant":"image","borderColor":"#0f4f8f","borderRadius":"20","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf