ity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"section-domestic-violence-body-20260717","layout":"single","locked":false,"modules":[{"id":"module-domestic-violence-body-20260717","name":"","text":"<h1>Domestic Violence</h1><h2>How Marinoff &amp; Associates Can Help</h2><p>At Marinoff &amp; Associates, we understand that domestic violence allegations are deeply personal, emotionally charged, and can move through the courts very quickly. An accusation alone can affect where you live, your contact with your children, your right to possess firearms, and your immigration status.</p><p>Our experienced legal team approaches these cases with urgency and discretion, examining the full context of the allegation, the evidence, and the procedures followed by law enforcement.</p><h2>What Are Domestic Violence Charges?</h2><p>Domestic violence allegations can arise alongside many underlying charges, including assault, harassment, criminal mischief, violation of a protection order, and other offenses involving a current or former intimate partner or household member, and more. These are only examples. We can help with these and any other related charge.</p><h2>How We Can Help:</h2><ul><li><p><strong>Immediate Guidance:</strong> We can advise you from the earliest moments of a case, including arrest, mandatory protection orders, and first court appearances, so early decisions do not compromise your defense.</p></li><li><p><strong>Court Representation:</strong> We can represent you at every stage of the legal process, from advisement and pre-trial hearings through trial.</p></li><li><p><strong>Protection Order Defense:</strong> We can help you respond to mandatory and civil protection orders and seek modifications that let you maintain lawful contact with your family and home.</p></li><li><p><strong>Collateral Consequences:</strong> We can help you understand and work to minimize effects on firearms rights, employment, housing, and immigration status.</p></li></ul><p>If you or a loved one is facing a domestic violence allegation, contact Marinoff &amp; Associates today for a consultation.</p>","type":"text","column":"","settings":{}}]},{"id":"b22a4855-b26c-43e3-9a2c-06dcfd7af403","title":"Footer","layout":"three-column","locked":false,"modules":[{"id":"module_1781127640512_v48dw","name":"Contact Us","text":"<h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Contact Us</strong></span></h3><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">303.619.1978‬</span></p><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">720.621.7635 - Se Habla Español</span></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"mailto:bmarinoff@brandonmarinoff.com\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">bmarinoff@brandonmarinoff.com</span></a></p><p></p><h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Address</strong></span></h3><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">12207 Pecos St. Suite 700</span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">Westminster, CO. 80234</span></a></p>","type":"text","column":"right","settings":{"text":"Contact Us","align":"left","textColor":"#173c61","h